const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_BASE_PREMIUM = 60;

const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];

const componentBasePremium = (items: Item[]): number => {
  const componentCounts = new Map<string, number>();
  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    }
  }
  let total = 0;
  for (const [type, count] of componentCounts) {
    if (count === BLOCK_SIZE) total += BLOCK_BASE_PREMIUM;
    else total += count * BASE_PREMIUM_BY_TYPE[type];
  }
  return total;
};

const totalBasePremium = (items: Item[]): number => {
  const mainItemsTotal = items
    .filter((item) => !COMPONENT_TYPES.has(item.type))
    .reduce((sum, item) => sum + basePremiumOf(item), 0);
  return mainItemsTotal + componentBasePremium(items);
};

